import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        // Read entire input, replace escaped newlines ("\\n") with real newlines
        InputStream in = System.in;
        byte[] allBytes = in.readAllBytes();
        String data = new String(allBytes);
        data = data.replace("\\n", "\n");
        StringTokenizer st = new StringTokenizer(data);
        int T = Integer.parseInt(st.nextToken());
        final int MAXV = 100000 + 5;
        int[] left = new int[MAXV];
        int[] right = new int[MAXV];
        int[] isChild = new int[MAXV];
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(st.nextToken());
            Arrays.fill(left, 0);
            Arrays.fill(right, 0);
            Arrays.fill(isChild, 0);
            int maxNode = 0;
            for (int i = 0; i < N - 1; i++) {
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                if (dir == 'L') left[p] = c; else right[p] = c;
                isChild[c] = 1;
                if (p > maxNode) maxNode = p;
                if (c > maxNode) maxNode = c;
            }
            int root = -1;
            if (N == 1) {
                // When there is only one node, its value is assumed to be 1 (as per sample)
                root = 1;
            } else {
                for (int i = 1; i <= maxNode; i++) {
                    if ((left[i] != 0 || right[i] != 0 || isChild[i] != 0) && isChild[i] == 0) {
                        root = i;
                        break;
                    }
                }
            }
            if (root == -1) {
                out.append('\n');
                continue;
            }
            ArrayDeque<Integer> stack = new ArrayDeque<>();
            stack.push(root);
            boolean first = true;
            while (!stack.isEmpty()) {
                int node = stack.pop();
                if (first) { out.append(node); first = false; } else out.append(' ').append(node);
                if (right[node] != 0) stack.push(right[node]);
                if (left[node] != 0) stack.push(left[node]);
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

